transform_js:
const nodesMap = {};
rawData.rows.forEach(r => {
  nodesMap[r.source] = true;
  nodesMap[r.target] = true;
});
const nodes = Object.keys(nodesMap).map(name => ({name}));
const links = rawData.rows.map(r => ({source: r.source, target: r.target, value: r.value}));
transformedData = { nodes, links };

echarts_js:
option = {
  tooltip: {
    trigger: 'item',
    triggerOn: 'mousemove'
  },
  series: [
    {
      type: 'sankey',
      data: transformedData.nodes,
      links: transformedData.links,
      right: '10%',
      emphasis: {
        focus: 'adjacency'
      },
      lineStyle: {
        color: 'source',
        curveness: 0.5
      },
      itemStyle: {
        borderWidth: 1,
        borderColor: '#111'
      },
      label: {
        color: '#333',
        fontFamily: 'Outfit, sans-serif'
      }
    }
  ]
};
